import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
from torchvision import transforms
from torchvision.models import resnet18, ResNet18_Weights
from PIL import Image
import io
import requests

# --- Configuration ---
MODEL_URL = "https://download.pytorch.org/models/resnet18-f37072fd.pth" # Example URL for ResNet18
NUM_CLASSES = 10  # Example: Number of classes in your custom dataset
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5
DEVICE = torch.device("cuda" if torch.cuda.is_available() else "cpu")

# --- Custom Dataset (Example) ---
# Replace this with your actual custom dataset loading logic
class CustomDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        # Simulate some dummy data
        self.data = [torch.randn(3, 224, 224) for _ in range(num_samples)]
        self.labels = [torch.randint(0, NUM_CLASSES, (1,)).item() for _ in range(num_samples)]

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.data[idx]
        label = self.labels[idx]
        if self.transform:
            # Convert tensor to PIL Image for torchvision transforms
            # This is a simplification; real data would already be PIL or numpy
            image = transforms.ToPILImage()(image)
            image = self.transform(image)
        return image, label

# --- Model Loading and Fine-tuning ---
def download_and_load_model(model_url, device):
    print(f"Downloading model from: {model_url}")
    try:
        response = requests.get(model_url, stream=True)
        response.raise_for_status()  # Raise an HTTPError for bad responses (4xx or 5xx)

        # Load the model from the in-memory bytes
        model_bytes = io.BytesIO(response.content)
        state_dict = torch.load(model_bytes, map_location=device)
        print("Model downloaded and loaded successfully.")
        return state_dict
    except requests.exceptions.RequestException as e:
        print(f"Error downloading model: {e}")
        return None
    except Exception as e:
        print(f"Error loading model state dict: {e}")
        return None

def fine_tune_model():
    # 1. Define transformations for your dataset
    # These should match the expectations of the pretrained model
    data_transforms = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # 2. Create your custom dataset and dataloaders
    print("Creating custom dataset and dataloaders...")
    train_dataset = CustomDataset(num_samples=1000, transform=data_transforms)
    val_dataset = CustomDataset(num_samples=200, transform=data_transforms) # For validation
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True, num_workers=4)
    val_loader = DataLoader(val_dataset, batch_size=BATCH_SIZE, shuffle=False, num_workers=4)
    print(f"Train samples: {len(train_dataset)}, Validation samples: {len(val_dataset)}")

    # 3. Load a pretrained model (e.g., ResNet18)
    # We'll use torchvision's built-in ResNet18 and then load the state_dict
    # This ensures the model architecture is correct.
    model = resnet18(weights=None) # Initialize with no weights
    print("Initialized ResNet18 architecture.")

    # 4. Download and load the state_dict
    pretrained_state_dict = download_and_load_model(MODEL_URL, DEVICE)
    if pretrained_state_dict is None:
        print("Failed to load pretrained model. Exiting.")
        return

    # Load the state_dict into the model
    # Set strict=False to ignore keys that don't match (e.g., the final classification layer)
    model.load_state_dict(pretrained_state_dict, strict=False)
    print("Loaded pretrained weights into the model.")

    # 5. Modify the final classification layer for your custom dataset
    num_ftrs = model.fc.in_features
    model.fc = nn.Linear(num_ftrs, NUM_CLASSES)
    model = model.to(DEVICE)
    print(f"Modified final layer to output {NUM_CLASSES} classes.")

    # 6. Define loss function and optimizer
    criterion = nn.CrossEntropyLoss()
    # Optimize only the newly added layer or fine-tune all layers
    # Example: Fine-tune all layers
    optimizer = optim.Adam(model.parameters(), lr=LEARNING_RATE)
    # Example: Optimize only the final layer
    # optimizer = optim.Adam(model.fc.parameters(), lr=LEARNING_RATE)

    # 7. Training loop
    print("Starting fine-tuning...")
    for epoch in range(NUM_EPOCHS):
        model.train()
        running_loss = 0.0
        correct_predictions = 0
        total_samples = 0

        for i, (inputs, labels) in enumerate(train_loader):
            inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)

            optimizer.zero_grad()

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = torch.max(outputs.data, 1)
            total_samples += labels.size(0)
            correct_predictions += (predicted == labels).sum().item()

        epoch_loss = running_loss / len(train_dataset)
        epoch_acc = correct_predictions / total_samples
        print(f"Epoch {epoch+1}/{NUM_EPOCHS}, Train Loss: {epoch_loss:.4f}, Train Acc: {epoch_acc:.4f}")

        # 8. Validation (optional but recommended)
        model.eval()
        val_loss = 0.0
        val_correct_predictions = 0
        val_total_samples = 0
        with torch.no_grad():
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)
                outputs = model(inputs)
                loss = criterion(outputs, labels)

                val_loss += loss.item() * inputs.size(0)
                _, predicted = torch.max(outputs.data, 1)
                val_total_samples += labels.size(0)
                val_correct_predictions += (predicted == labels).sum().item()

        val_epoch_loss = val_loss / len(val_dataset)
        val_epoch_acc = val_correct_predictions / val_total_samples
        print(f"Epoch {epoch+1}/{NUM_EPOCHS}, Val Loss: {val_epoch_loss:.4f}, Val Acc: {val_epoch_acc:.4f}")

    print("Fine-tuning complete!")

    # 9. Save the fine-tuned model
    torch.save(model.state_dict(), "fine_tuned_model.pth")
    print("Fine-tuned model saved as 'fine_tuned_model.pth'")

if __name__ == "__main__":
    print(f"Using device: {DEVICE}")
    fine_tune_model()